import React from "react";
import { downtimeData } from "./downtime-graph-hooks";
import GraphContainer from "../graphContainer";
import { ResponsiveLine } from "@nivo/line";

const SmartMaintenanceGraph = () => (
  <GraphContainer title="Monthly Downtime (Cumulative)">
    <div style={{ width: "100%", height: "100%" }}>
      <ResponsiveLine
        data={downtimeData}
        margin={{ top: 17, right: 30, bottom: 80, left: 60 }}
        xScale={{ type: "point" }}
        yScale={{
          type: "linear",
          min: 0,
          max: 160,
          stacked: true,
          reverse: false,
        }}
        axisBottom={{
          orient: "bottom",
          tickSize: 5,
          tickPadding: 5,
          tickRotation: 0,
          legend: "Month",
          legendOffset: 36,
          legendPosition: "middle",
        }}
        axisLeft={{
          orient: "left",
          tickSize: 5,
          tickPadding: 5,
          tickRotation: 0,
          legend: "Downtime (Hours)",
          legendOffset: -50,
          legendPosition: "middle",
        }}
        colors={{ scheme: "nivo" }}
        pointSize={5}
        pointColor={{ theme: "background" }}
        pointBorderWidth={2}
        pointBorderColor={{ from: "serieColor" }}
        pointLabel="y"
        pointLabelYOffset={-50}
        useMesh={true}
        legends={[
          {
            anchor: "bottom-left",
            direction: "row",
            justify: false,
            translateX: -50,
            translateY: 53,
            itemsSpacing: 40,
            itemDirection: "left-to-right",
            itemWidth: 20,
            itemHeight: 20,
            itemOpacity: 0.75,
            symbolSize: 12,
            symbolShape: "circle",
            symbolBorderColor: "rgba(0, 0, 0, .5)",
            effects: [
              {
                on: "hover",
                style: {
                  itemBackground: "rgba(0, 0, 0, .03)",
                  itemOpacity: 1,
                },
              },
            ],
          },
        ]}
      />
    </div>
  </GraphContainer>
);

export default SmartMaintenanceGraph;
